import sys from pathlib import Path sys.path.insert(0, str(Path(__file__).parent.parent))
from sentence_transformers import SentenceTransformer import numpy as np import argparse import json from _utils.lancedb_helper import LanceDBHelper
db = LanceDBHelper()
import subprocess import os import time import re import sqlite3 from pathlib import Path from datetime import datetime
# --- THE CONTRACT (Embedded) --- CONTRACT = { "stage": "01ingest", "required_json_fields": ["video_id", "title", "url", "slug"], "required_files": ["{slug}.mp3", "{slug}.txt"] }
def slugify(text): """Converts a title into a safe filename/folder slug.""" text = re.sub(r'[^a-zA-Z0-9\s-]', '', text) text = re.sub(r'[\s-]+', '-', text).strip('-') return text.lower()
def clean_vtt(vtt_path, txt_path): """Manually converts VTT to clean TXT without FFmpeg or other tools.""" if not vtt_path.exists(): return False try: content = vtt_path.read_text(encoding="utf-8") # Remove VTT header and timestamps/metadata content = re.sub(r'WEBVTT.*?\n\n', '', content, flags=re.DOTALL) content = re.sub(r'\d{2}:\d{2}:\d{2}.\d{3} --> \d{2}:\d{2}:\d{2}.\d{3}.*?\n', '', content) content = re.sub(r'<.*?>', '', content) # Remove tags like
# Merge lines and remove duplicates (common in auto-subs) lines = [] last_line = "" for line in content.splitlines(): line = line.strip() if line and line != last_line: lines.append(line) last_line = line
txt_path.write_text(" ".join(lines), encoding="utf-8") return True except Exception as e: print(f"Error cleaning VTT: {e}") return False
def emit_event(slug, verb, payload=None): """Writes an event to the dashboard's ticker feed.""" dash_public = Path(__file__).parent.parent / "Dashboard" / "public" event_file = dash_public / "events.json" event_file.parent.mkdir(parents=True, exist_ok=True)
now = int(time.time() * 1000) event = { "id": f"evt_{now}_{slug}", "ts": now, "verb": verb, "job_id": slug, "payload": payload or {} }
events = [] if event_file.exists(): try: with open(event_file, "r", encoding="utf-8") as f: events = json.load(f) except: pass
events.append(event) events = events[-100:]
with open(event_file, "w", encoding="utf-8") as f: json.dump(events, f, indent=2)
def process_single_video(url, slug=None): script_dir = Path(__file__).parent
emit_event(slug or "pending", "01ingest.init", {"url": url}) print(f"🔍 Fetching metadata for {url}...")
try: # Get ID and Title info_raw = subprocess.check_output([ "yt-dlp", "--get-id", "--get-title", "--no-playlist", url ]).decode().strip().split('\n')
vid_id = info_raw[1] if len(info_raw) > 1 else info_raw[0] title = info_raw[0]
if not slug: slug = slugify(title)
slug_dir = script_dir / slug slug_dir.mkdir(parents=True, exist_ok=True)
emit_event(slug, "01ingest.discovery", {"url": url, "title": title, "vid": vid_id}) print(f"🚀 Ingesting: {slug}")
# 2. Download Audio emit_event(slug, "01ingest.download.started")
try: has_ffmpeg = subprocess.run(["ffmpeg", "-version"], capture_output=True).returncode == 0 except: has_ffmpeg = False
if has_ffmpeg: subprocess.run([ "yt-dlp", "-x", "--audio-format", "mp3", "-o", f"{slug_dir}/{slug}.%(ext)s", "--no-playlist", url ], check=True) else: print("⚠️ No FFmpeg. Downloading m4a and renaming to .mp3") subprocess.run([ "yt-dlp", "-f", "bestaudio[ext=m4a]/bestaudio", "-o", f"{slug_dir}/{slug}.%(ext)s", "--no-playlist", url ], check=True)
# Find whatever audio we got and rename to .mp3 to satisfy the contract for ext in ['.m4a', '.webm', '.opus']: temp_file = slug_dir / f"{slug}{ext}" if temp_file.exists(): temp_file.replace(slug_dir / f"{slug}.mp3") break
# 3. Download Captions emit_event(slug, "01ingest.transcript.started") subprocess.run([ "yt-dlp", "--skip-download", "--write-auto-sub", "--sub-langs", "en", "-o", f"{slug_dir}/{slug}", "--no-playlist", url ], check=False)
# Find VTT and convert to TXT manually vtt_found = False for f in slug_dir.glob(f"{slug}.*.vtt"): if clean_vtt(f, slug_dir / f"{slug}.txt"): vtt_found = True f.unlink() # Delete the vtt break
if not vtt_found: print("⚠️ No captions found. Creating empty transcript to avoid contract breach.") (slug_dir / f"{slug}.txt").write_text("[No captions available]", encoding="utf-8")
emit_event(slug, "01ingest.download.done")
# 4. Finalize metadata = { "video_id": vid_id, "title": title, "url": url, "slug": slug }
with open(slug_dir / "ingest.json", "w", encoding="utf-8") as f: json.dump(metadata, f, indent=2)
emit_event(slug, "saved to 01ingest", {"hash_id": f"saved_{slug}"}) print(f"✨ Saved to 01ingest: {slug_dir}")
except Exception as e: emit_event(slug or "failed", "01ingest.failed", {"reason": str(e)}) print(f"❌ INGEST FAILED: {e}")
# Vectorize model = SentenceTransformer('all-MiniLM-L6-v2') out_file = Path(__file__).parent / f'{slug}.json' if 'slug' in dir() else Path(__file__).parent / f'{Path(__file__).stem}.json' if out_file.exists(): with open(out_file) as f: d=json.load(f) for k,v in d.items(): if isinstance(v,str) and len(v)>50: d[f'{k}_vec']=model.encode(v).tolist() with open(out_file,'w') as f: json.dump(d,f,indent=2) print('Vectorized')
# Upsert to LanceDB try: db.upsert( record_id=slug, stage='01ingest', record_type='transcript', data={'url': url, 'title': title, 'slug': slug, 'transcript': open(slug_dir/f"{slug}.txt").read()[:2000]}, vector_field='transcript' ) print(f"💾 Saved to LanceDB: {slug}") except Exception as e: print(f"⚠️ LanceDB error: {e}")
if __name__ == "__main__": parser = argparse.ArgumentParser() parser.add_argument("--url", required=True) parser.add_argument("--slug", required=False) args = parser.parse_args() process_single_video(args.url, args.slug)

