# 08commentary/08commentary_vdb.py - Classify commentary, store in VDB import sys import json import re import requests from pathlib import Path
sys.path.insert(0, str(Path(__file__).parent.parent)) from _utils.vdb_pipeline import get_all_suttas, save_to_vdb, stage_exists, get_stage_count
OLLAMA_MODEL = "llama3.2:3b" OLLAMA_URL = "http://127.0.0.1:11434/api/generate"
def classify_segment(text): if len(text) < 30: return "other" prompt = f"Classify: caution/practice/sidenote/interpretation. Return only one word.\n\n{text[:300]}" try: resp = requests.post(OLLAMA_URL, json={"model": OLLAMA_MODEL, "prompt": prompt, "stream": False, "options": {"temperature": 0.1}}, timeout=30) result = resp.json().get("response", "").strip().lower() for cat in ["caution", "practice", "sidenote", "interpretation"]: if cat in result: return cat except: pass return "other"
def split_commentary(commentary): markers = [r'[Ii]\s+just\s+stopped', r'[Ii]\'?ll\s+just\s+stop', r'[Ii]\'?d\s+just\s+like\s+to\s+commend', r'[Ff]irstly\s+you\s+notice'] pattern = '|'.join(markers) matches = list(re.finditer(pattern, commentary, re.IGNORECASE)) if not matches: return [commentary] if commentary else [] segments, prev = [], 0 for m in matches: if m.start() > prev: seg = commentary[prev:m.start()].strip() if seg: segments.append(seg) prev = m.start() if prev < len(commentary): segments.append(commentary[prev:].strip()) return segments
print("=" * 60) print("08commentary - Classify commentary (VDB Only)") print("=" * 60)
if not stage_exists("03segment"): print("❌ No data in stage 03segment. Run 03segment first!") sys.exit(1)
suttas = get_all_suttas("03segment") print(f"📖 Processing {len(suttas)} suttas from VDB\n")
for sutta in suttas: sutta_id = sutta.get('sutta_id') or sutta.get('id', '') commentary = sutta.get('commentary', '')
if not commentary: print(f"⚠️ {sutta_id}: No commentary") continue
print(f"📖 {sutta_id}")
segments = split_commentary(commentary) classified = {"cautions": [], "practices": [], "sidenotes": [], "interpretations": [], "other": []}
for seg in segments: if len(seg) < 30: continue cat = classify_segment(seg) classified[cat].append({"text": seg[:300], "full_text": seg}) print(f" → {cat}: {seg[:50]}...")
comment_data = { "sutta_id": sutta_id, "classified_segments": classified, "total_segments": len(segments) }
save_to_vdb(sutta_id, "08commentary", "commentary", comment_data) print(f" 💾 Saved to VDB (stage=08commentary)\n")
print(f"🎉 Done! Total commentaries in VDB: {get_stage_count('08commentary')}")

# 10generate/10generate.py
# Generate learning content from VDB (LanceDB only)

import sys
import json
import re
from pathlib import Path
from datetime import datetime
import requests

sys.path.insert(0, str(Path(__file__).parent.parent))
from _utils.vdb_pipeline import get_all_suttas, save_to_vdb, stage_exists

OLLAMA_MODEL = "llama3.2:3b"
OLLAMA_URL = "http://127.0.0.1:11434/api/generate"

def generate_mcq(sutta_text: str, sutta_name: str) -> dict:
    """Generate multiple choice question"""
    prompt = f"""Generate ONE multiple choice question from this sutta.
Return ONLY JSON: {{"question": "...", "options": ["A", "B", "C", "D"], "correct": "A", "explanation": "..."}}

Sutta: {sutta_name}
Text: {sutta_text[:1000]}"""

    try:
        resp = requests.post(OLLAMA_URL, json={
            "model": OLLAMA_MODEL,
            "prompt": prompt,
            "stream": False,
            "options": {"temperature": 0.3}
        }, timeout=60)
        result = resp.json().get("response", "")
        match = re.search(r'\{.*\}', result, re.DOTALL)
        if match:
            return json.loads(match.group())
    except Exception as e:
        print(f"   MCQ error: {e}")
    return {"question": "No question generated", "options": [], "correct": "", "explanation": ""}

def generate_text(sutta_text: str, sutta_name: str, content_type: str) -> str:
    """Generate vow, caution, or practice"""
    prompts = {
        "vow": f"Create a ONE SENTENCE vow from this sutta. Return only the vow text:\n\n{sutta_text[:800]}",
        "caution": f"Extract the CAUTION from this sutta. One short sentence:\n\n{sutta_text[:800]}",
        "practice": f"Extract the PRACTICE from this sutta. One short sentence:\n\n{sutta_text[:800]}"
    }

    try:
        resp = requests.post(OLLAMA_URL, json={
            "model": OLLAMA_MODEL,
            "prompt": prompts[content_type],
            "stream": False,
            "options": {"temperature": 0.3}
        }, timeout=60)
        return resp.json().get("response", "").strip()
    except Exception as e:
        print(f"   {content_type} error: {e}")
        return ""

def main():
    print("=" * 60)
    print("10generate - Generate MCQ, Vow, Caution, Practice")
    print("=" * 60)

    # Check if we have suttas in VDB
    if not stage_exists("04names"):
        print("❌ No suttas found in VDB (stage=04names).")
        print("   Run 04names first to populate the VDB!")
        return

    # Get all suttas from VDB
    suttas = get_all_suttas("04names")
    print(f"\n📖 Processing {len(suttas)} suttas from VDB\n")

    for sutta in suttas:
        sutta_id = sutta.get('sutta_id') or sutta.get('id', '')
        sutta_name = sutta.get('sutta_name', 'Unknown')
        sutta_text = sutta.get('sutta', '')

        if not sutta_text:
            print(f"⚠️ {sutta_id}: No sutta text")
            continue

        print(f"📖 {sutta_id} - {sutta_name}")

        # Generate content
        print("   Generating MCQ...")
        mcq = generate_mcq(sutta_text, sutta_name)

        print("   Generating Vow...")
        vow = generate_text(sutta_text, sutta_name, "vow")

        print("   Generating Caution...")
        caution = generate_text(sutta_text, sutta_name, "caution")

        print("   Generating Practice...")
        practice = generate_text(sutta_text, sutta_name, "practice")

        # Prepare data for VDB
        generated_data = {
            "sutta_id": sutta_id,
            "sutta_name": sutta_name,
            "mcq_quiz": mcq,
            "vow": vow,
            "caution": caution,
            "practice": practice,
            "generated_at": datetime.now().isoformat()
        }

        # Save to VDB
        try:
            save_to_vdb(sutta_id, "10generate", "generated_content", generated_data)
            print(f"   ✅ Saved to VDB (stage=10generate)")
        except Exception as e:
            print(f"   ⚠️ VDB error: {e}")

        # Show preview
        if vow:
            print(f"      Vow: {vow[:60]}...")
        if caution:
            print(f"      Caution: {caution[:60]}...")
        if practice:
            print(f"      Practice: {practice[:60]}...")
        print()

    print(f"🎉 Done! Generated content saved to VDB (stage=10generate)")

if __name__ == "__main__":
    main()

﻿# 11translate/11translate.py
# Translate all sutta content to Japanese

import sys
import json
import re
from pathlib import Path
from datetime import datetime
import requests

sys.path.insert(0, str(Path(__file__).parent.parent))
from _utils.vdb_pipeline import get_all_suttas, save_to_vdb, stage_exists, get_sutta

OLLAMA_MODEL = "qwen2.5:14b"  # Best for Japanese translation
OLLAMA_URL = "http://127.0.0.1:11434/api/generate"

def translate_text(text: str, field_name: str, max_length: int = 2000) -> str:
    """Translate English text to Japanese"""
    if not text or len(text) < 10:
        return ""

    prompt = f"""Translate this Buddhist {field_name} from English to Japanese.
Return ONLY the Japanese translation, no explanations.

English: {text[:max_length]}

Japanese translation:"""

    try:
        resp = requests.post(OLLAMA_URL, json={
            "model": OLLAMA_MODEL,
            "prompt": prompt,
            "stream": False,
            "options": {"temperature": 0.1}
        }, timeout=90)
        result = resp.json().get("response", "").strip()
        return result
    except Exception as e:
        print(f"   Translation error for {field_name}: {e}")
        return text  # Return original if translation fails

def translate_mcq(mcq: dict) -> dict:
    """Translate MCQ question, options, and explanation"""
    if not mcq:
        return mcq

    translated = {}

    if "question" in mcq:
        translated["question"] = translate_text(mcq["question"], "MCQ question", 500)

    if "options" in mcq and isinstance(mcq["options"], list):
        translated["options"] = []
        for opt in mcq["options"]:
            translated["options"].append(translate_text(opt, "MCQ option", 200))

    if "explanation" in mcq:
        translated["explanation"] = translate_text(mcq["explanation"], "MCQ explanation", 500)

    # Keep correct answer as is (A, B, C, D)
    if "correct" in mcq:
        translated["correct"] = mcq["correct"]

    return translated

def main():
    print("=" * 60)
    print("11translate - Translate all content to Japanese")
    print("=" * 60)

    # Check if we have source data
    if not stage_exists("04names"):
        print("❌ No suttas found in VDB (stage=04names). Run 01-04 first!")
        return

    if not stage_exists("07keys"):
        print("⚠️ No chains found (stage=07keys). Skipping chain translation")

    if not stage_exists("08commentary"):
        print("⚠️ No commentary classifications found (stage=08commentary)")

    if not stage_exists("10generate"):
        print("⚠️ No generated content found (stage=10generate)")

    # Get all suttas
    suttas = get_all_suttas("04names")
    print(f"\n📖 Translating {len(suttas)} suttas to Japanese\n")

    for sutta in suttas:
        sutta_id = sutta.get('sutta_id') or sutta.get('id', '')
        print(f"📖 {sutta_id}")

        # 1. Translate sutta text
        print("   Translating sutta text...")
        sutta_text_jp = translate_text(sutta.get('sutta', ''), "sutta", 1500)

        # 2. Translate commentary
        print("   Translating commentary...")
        commentary_jp = translate_text(sutta.get('commentary', ''), "commentary", 1500)

        # 3. Get and translate chains
        chain_data = get_sutta(sutta_id, "07keys")
        chain_jp = {}
        if chain_data:
            print("   Translating chains...")
            chain = chain_data.get('chain', {})
            items = chain.get('items', [])
            translated_items = []
            for item in items:
                translated_items.append(translate_text(item, "chain item", 200))
            chain_jp = {
                "category": translate_text(chain.get('category', ''), "category", 100),
                "items": translated_items,
                "count": len(translated_items),
                "is_ordered": chain.get('is_ordered', True)
            }

        # 4. Get and translate commentary classifications
        commentary_data = get_sutta(sutta_id, "08commentary")
        commentary_jp_data = {}
        if commentary_data:
            print("   Translating commentary classifications...")
            classified = commentary_data.get('classified_segments', {})
            for seg_type in ['cautions', 'practices', 'sidenotes', 'interpretations']:
                segments = classified.get(seg_type, [])
                translated_segments = []
                for seg in segments:
                    translated_segments.append({
                        "text": translate_text(seg.get('text', ''), f"{seg_type}", 300),
                        "full_text": translate_text(seg.get('full_text', ''), f"{seg_type}_full", 500),
                        "timestamp": seg.get('timestamp', {})
                    })
                commentary_jp_data[seg_type] = translated_segments

        # 5. Get and translate generated content
        generated_data = get_sutta(sutta_id, "10generate")
        generated_jp = {}
        if generated_data:
            print("   Translating generated content...")
            generated_jp = {
                "mcq_quiz": translate_mcq(generated_data.get('mcq_quiz', {})),
                "vow": translate_text(generated_data.get('vow', ''), "vow", 300),
                "caution": translate_text(generated_data.get('caution', ''), "caution", 300),
                "practice": translate_text(generated_data.get('practice', ''), "practice", 300)
            }

        # Build Japanese translation record
        jp_record = {
            "sutta_id": sutta_id,
            "sutta_name": sutta.get('sutta_name', ''),
            "sc_link": sutta.get('sc_link', ''),
            "sutta_jp": sutta_text_jp,
            "commentary_jp": commentary_jp,
            "chain_jp": chain_jp,
            "commentary_classifications_jp": commentary_jp_data,
            "generated_content_jp": generated_jp,
            "translated_at": datetime.now().isoformat()
        }

        # Save to VDB
        try:
            save_to_vdb(sutta_id, "11translate", "japanese", jp_record)
            print(f"   ✅ Saved to VDB (stage=11translate)")
        except Exception as e:
            print(f"   ⚠️ VDB error: {e}")

        # Show preview
        if sutta_text_jp:
            print(f"      Sutta preview: {sutta_text_jp[:60]}...")
        print()

    print(f"🎉 Done! Japanese translations saved to VDB (stage=11translate)")

if __name__ == "__main__":
    main()

