﻿import json
import lancedb
import numpy as np
from pathlib import Path
from sentence_transformers import SentenceTransformer

class LanceDBHelper:
    def __init__(self, db_path=None):
        if db_path is None:
            db_path = Path(__file__).parent.parent / "vectordb" / "pipeline.lance"
        self.db_path = Path(db_path)
        self.db_path.parent.mkdir(parents=True, exist_ok=True)
        self.db = lancedb.connect(str(self.db_path))
        self.model = SentenceTransformer('all-MiniLM-L6-v2')
        self.table_name = "pipeline_data"
        self._init_table()

    def _init_table(self):
        if self.table_name not in self.db.table_names():
            sample = [{'id': 'init', 'stage': 'init', 'type': 'init', 'vector': [0.0]*384, 'data': '{}', 'timestamp': 0}]
            self.db.create_table(self.table_name, sample, mode="overwrite")
            self.db.open_table(self.table_name).delete("id = 'init'")

    def vectorize(self, text, max_length=2000):
        if not text:
            return [0.0]*384
        return self.model.encode(text[:max_length]).tolist()

    def upsert(self, record_id, stage, record_type, data, vector_field=None, vector_text=None):
        import time
        vector = None
        if vector_field and vector_field in data:
            vector = self.vectorize(str(data[vector_field]))
        elif vector_text:
            vector = self.vectorize(vector_text)

        record = {
            'id': record_id,
            'stage': stage,
            'type': record_type,
            'data': json.dumps(data, ensure_ascii=False),
            'timestamp': int(time.time() * 1000)
        }
        if vector:
            record['vector'] = vector

        table = self.db.open_table(self.table_name)
        existing = table.search().where(f"id = '{record_id}' and stage = '{stage}'").limit(1).to_list()
        if existing:
            table.delete(f"id = '{record_id}' and stage = '{stage}'")
        table.add([record])
        return True

    def get_latest(self, record_id):
        table = self.db.open_table(self.table_name)
        results = table.search().where(f"id = '{record_id}'").limit(1).to_list()
        return json.loads(results[0]['data']) if results else None

    def search_similar(self, query_text, record_type=None, limit=10):
        query_vec = self.vectorize(query_text)
        table = self.db.open_table(self.table_name)
        if record_type:
            results = table.search(query_vec).where(f"type = '{record_type}'").limit(limit).to_list()
        else:
            results = table.search(query_vec).limit(limit).to_list()
        return [{'id': r['id'], 'stage': r['stage'], 'type': r['type'], 
                 'data': json.loads(r['data']), 'score': float(1 - r['_distance'])} for r in results]

﻿# _utils/vdb_pipeline.py import json from pathlib import Path from typing import Optional, List, Dict, Any from _utils.lancedb_helper import LanceDBHelper
_db = None
def get_db(): global _db if _db is None: _db = LanceDBHelper() return _db
def get_sutta(sutta_id: str, stage: str) -> Optional[Dict]: """Get data from specific stage""" db = get_db() return db.get_by_stage(sutta_id, stage)
def get_all_suttas(stage: str, limit: int = 1000) -> List[Dict]: """Get all suttas from a stage""" db = get_db() table = db.db.open_table(db.table_name) results = table.search().where(f"stage = '{stage}'").limit(limit).to_list() return [json.loads(r['data']) for r in results]
def get_suttas_by_type(record_type: str, limit: int = 1000) -> List[Dict]: """Get all items by type (sutta, manga, chain, etc.)""" db = get_db() table = db.db.open_table(db.table_name) results = table.search().where(f"type = '{record_type}'").limit(limit).to_list() return [json.loads(r['data']) for r in results]
def save_to_vdb(record_id: str, stage: str, record_type: str, data: Dict, vector_field: str = None): """Save data to VDB""" db = get_db() return db.upsert(record_id, stage, record_type, data, vector_field)
def stage_exists(stage: str) -> bool: """Check if any data exists for a stage""" db = get_db() table = db.db.open_table(db.table_name) results = table.search().where(f"stage = '{stage}'").limit(1).to_list() return len(results) > 0
def get_stage_count(stage: str) -> int: """Get count of records in a stage""" db = get_db() table = db.db.open_table(db.table_name) results = table.search().where(f"stage = '{stage}'").limit(10000).to_list() return len(results)

